4155 std::tuple<Value *, FPClassTest, FPClassTest>
4156 llvm::fcmpImpliesClass(CmpInst::Predicate Pred, const Function &F, Value *LHS,
4157                        const APFloat &ConstRHS, bool LookThroughSrc) {
4158   // We can refine checks against smallest normal / largest denormal to an
4159   // exact class test.
4160   if (!ConstRHS.isNegative() && ConstRHS.isSmallestNormalized()) {
4161     Value *Src = LHS;
4162     const bool IsFabs = LookThroughSrc && match(LHS, m_FAbs(m_Value(Src)));
4163 
4164     FPClassTest Mask;
4165     // Match pattern that's used in __builtin_isnormal.
4166     switch (Pred) {
4167     case FCmpInst::FCMP_OLT:
4168     case FCmpInst::FCMP_UGE: {
4169       // fcmp olt x, smallest_normal -> fcNegInf|fcNegNormal|fcSubnormal|fcZero
4170       // fcmp olt fabs(x), smallest_normal -> fcSubnormal|fcZero
4171       // fcmp uge x, smallest_normal -> fcNan|fcPosNormal|fcPosInf
4172       // fcmp uge fabs(x), smallest_normal -> ~(fcSubnormal|fcZero)
4173       Mask = fcZero | fcSubnormal;
4174       if (!IsFabs)
4175         Mask |= fcNegNormal | fcNegInf;
4176 
4177       break;
4178     }
4179     case FCmpInst::FCMP_OGE:
4180     case FCmpInst::FCMP_ULT: {
4181       // fcmp oge x, smallest_normal -> fcPosNormal | fcPosInf
4182       // fcmp oge fabs(x), smallest_normal -> fcInf | fcNormal
4183       // fcmp ult x, smallest_normal -> ~(fcPosNormal | fcPosInf)
4184       // fcmp ult fabs(x), smallest_normal -> ~(fcInf | fcNormal)
4185       Mask = fcPosInf | fcPosNormal;
4186       if (IsFabs)
4187         Mask |= fcNegInf | fcNegNormal;
4188       break;
4189     }
4190     default:
4191       return fcmpImpliesClass(Pred, F, LHS, ConstRHS.classify(),
4192                               LookThroughSrc);
4193     }
4194 
4195     // Invert the comparison for the unordered cases.
4196     if (FCmpInst::isUnordered(Pred))
4197       Mask = ~Mask;
4198 
4199     return exactClass(Src, Mask);
4200   }
4201 
4202   return fcmpImpliesClass(Pred, F, LHS, ConstRHS.classify(), LookThroughSrc);
4203 }
