4216 static FPClassTest computeKnownFPClassFromAssumes(const Value *V,
4217                                                   const SimplifyQuery &Q) {
4218   FPClassTest KnownFromAssume = fcAllFlags;
4219 
4220   // Try to restrict the floating-point classes based on information from
4221   // assumptions.
4222   for (auto &AssumeVH : Q.AC->assumptionsFor(V)) {
4223     if (!AssumeVH)
4224       continue;
4225     CallInst *I = cast<CallInst>(AssumeVH);
4226     const Function *F = I->getFunction();
4227 
4228     assert(F == Q.CxtI->getParent()->getParent() &&
4229            "Got assumption for the wrong function!");
4230     assert(I->getCalledFunction()->getIntrinsicID() == Intrinsic::assume &&
4231            "must be an assume intrinsic");
4232 
4233     if (!isValidAssumeForContext(I, Q.CxtI, Q.DT))
4234       continue;
4235 
4236     CmpInst::Predicate Pred;
4237     Value *LHS, *RHS;
4238     uint64_t ClassVal = 0;
4239     if (match(I->getArgOperand(0), m_FCmp(Pred, m_Value(LHS), m_Value(RHS)))) {
4240       const APFloat *CRHS;
4241       if (match(RHS, m_APFloat(CRHS))) {
4242         auto [CmpVal, MaskIfTrue, MaskIfFalse] =
4243             fcmpImpliesClass(Pred, *F, LHS, *CRHS, LHS != V);
4244         if (CmpVal == V)
4245           KnownFromAssume &= MaskIfTrue;
4246       }
4247     } else if (match(I->getArgOperand(0),
4248                      m_Intrinsic<Intrinsic::is_fpclass>(
4249                          m_Value(LHS), m_ConstantInt(ClassVal)))) {
4250       KnownFromAssume &= static_cast<FPClassTest>(ClassVal);
4251     }
4252   }
4253 
4254   return KnownFromAssume;
4255 }
